import React from 'react';

const Header = () => {
    return (
        <header style={styles.header}>
            <div style={styles.logo}>MyLogo</div>
            <input type="text" placeholder="Search..." style={styles.search} />
            <nav style={styles.nav}>
                <a href="#events" style={styles.navLink}>Events</a>
                <a href="#clubs" style={styles.navLink}>Clubs</a>
                <a href="#forms" style={styles.navLink}>Forms</a>
                <a href="#talks" style={styles.navLink}>Talks</a>
            </nav>
            <button style={styles.loginBtn}>Log In</button>
        </header>
    );
};

const styles = {
    header: {
        display: 'flex',
        alignItems: 'center',
        padding: '10px 20px',
        backgroundColor: '#041E42',
        color: 'white',
    },
    logo: {
        fontWeight: 'bold',
        fontSize: '1.5rem',
        marginRight: '20px',
    },
    search: {
        flexGrow: 1,
        padding: '5px 10px',
        fontSize: '1rem',
        borderRadius: '4px',
        border: 'none',
    },
    nav: {
        display: 'flex',
        gap: '15px',
        marginLeft: '20px',
    },
    navLink: {
        color: 'white',
        textDecoration: 'none',
        fontWeight: '500',
    },
    loginBtn: {
        marginLeft: '20px',
        padding: '8px 15px',
        fontSize: '1rem',
        borderRadius: '4px',
        border: 'none',
        cursor: 'pointer',
    },
};

export default Header;
